        if let typeIdentifier = type.as(AttributedTypeSyntax.self), let specifier = typeIdentifier.specifier {
            if specifier.tokenKind == .keyword(.inout) {
                isInOut = true
            } else {
                assertionFailure("Unhandled specifier")
