                    expect(typeName.isArray).to(beTrue())
                    expect(typeName.generic?.typeParameters).to(haveCount(1))
                }

                it("handles multi-parameter generic with trailing comma") {
                    let typeName = variableTypeName("Dictionary<String, Int,>")
                    expect(typeName.isDictionary).to(beTrue())
                    expect(typeName.generic?.typeParameters).to(haveCount(2))
                }

                it("handles custom generic type with trailing comma") {
                    let typeName = variableTypeName("Foo<String, Int,>")
                    expect(typeName.isGeneric).to(beTrue())
                    expect(typeName.generic?.typeParameters).to(haveCount(2))
                }
            }
        }
    }
}

